import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"20. Casual Conversion","description":"","frontmatter":{"title":"20. Casual Conversion","eba":"Nurses and Midwives 2024-2028","topics":["employment","casual-conversion"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/20-casual-conversion.md","filePath":"ebas/nurses-midwives/employment-types/20-casual-conversion.md"}'),n={name:"ebas/nurses-midwives/employment-types/20-casual-conversion.md"};function i(a,e,p,l,h,u){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_20-casual-conversion" tabindex="-1">20. Casual Conversion <a class="header-anchor" href="#_20-casual-conversion" aria-label="Permalink to &quot;20. Casual Conversion&quot;">​</a></h1><p><strong>20.1</strong> Employee requests</p><p><strong>(a)</strong> A Casual Employee may make a request of an Employer under this clause if:</p><p><strong>(i)</strong> the Employee has been employed by the Employer for a period of at least 6 months beginning the day the employment started;</p><p><strong>(ii)</strong> the Employee has, in the period of 6 months ending the day the request is given, worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Employee could continue to work as a full-time Employee or part-time Employee (as the case may be); and</p><p><strong>(iii)</strong> all of the following apply:</p><p><strong>(A)</strong> the Employee has not, at any time during the period referred to in subclause 20.1(a)(ii), refused an offer for casual conversion made to the Employee;</p><p><strong>(B)</strong> the Employer has not, at any time during that period, given the Employee a notice in accordance with subclause 20.4(a);</p><p><strong>(C)</strong> the Employer has not, at any time during that period, given a response to the Employee under clause 20.2 refusing a previous request made under this clause;</p><p><strong>(D)</strong> the request is not made during the period of 21 days after the period referred to in subclause 20.1(a)(i).</p><p><strong>(b)</strong> The request must:</p><p><strong>(i)</strong> be in writing;</p><p><strong>(ii)</strong> be a request for the Employee to convert:</p><p><strong>(A)</strong> for an Employee that has worked the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 20.1(a)(ii) – to full-time employment; or</p><p><strong>(B)</strong> for an Employee that has worked less than the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 20.1(a)(ii) – to part-time employment that is consistent with the regular pattern of hours or shifts worked during that period; and</p><p><strong>(iii)</strong> be given to the Employer.</p><p><strong>20.2</strong> Employer must give a response</p><p>The Employer must give the Employee a written response to the request made under clause 20.1 within 21 days after the request is given to the Employer, stating whether the Employer grants or refuses the request.</p><p><strong>20.3</strong> Refusals of requests</p><p><strong>(a)</strong> The Employer must not refuse the request unless:</p><p><strong>(i)</strong> the Employer has consulted the Employee;</p><p><strong>(ii)</strong> there are reasonable grounds the refuse the request; and</p><p><strong>(iii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of refusing the request.</p><p><strong>(b)</strong> Without limiting subclause 20.3(a), reasonable grounds for refusing a request include the following:</p><p><strong>(i)</strong> it would require a significant adjustment to the Employee’s hours of work in order for the Employee to be employed as a full-time Employee or part-time Employee;</p><p><strong>(ii)</strong> the Employee’s position will cease to exist in the period of 12 months after giving the request;</p><p><strong>(iii)</strong> the hours of work which the Employee is required to perform will be significantly reduced in the period of 12 months after giving the request;</p><p><strong>(iv)</strong> there will be a significant change in either or both of the following in the period of 12 months after giving the request:</p><p><strong>(A)</strong> the days on which the Employee’s hours of work are required to be performed;</p><p><strong>(B)</strong> the times at which the Employee’s hours of work are required to be performed;</p><p>which cannot be accommodated within the days or times the Employee is available to work during that period; and</p><p><strong>(v)</strong> granting the request would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>(c)</strong> If the Employer refuses the request, the written response under clause 20.2 must include details of the reasons for the refusal.</p><p><strong>20.4</strong> Grants of requests</p><p><strong>(a)</strong> If the Employer grants the request, the Employer must, within 21 days after the day the request is given to the Employer, give written notice to the Employee of the following:</p><p><strong>(i)</strong> whether the Employee is converting to full-time employment or part- time employment;</p><p><strong>(ii)</strong> the Employee&#39;s pattern of hours or shifts after the conversion takes effect; and</p><p><strong>(iii)</strong> the day the Employee&#39;s conversion to full-time or part-time employment takes effect.</p><p><strong>(b)</strong> However, the Employer must discuss with the Employee the matters the Employer intends to specify for the purposes of subclause 20.4(a)(i)-(iii) before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 20.4(a)(iii) must be the first day of the Employee&#39;s first full pay period that starts after the day the notice is given, unless the Employee and Employer agree to another day.</p><p><strong>(d)</strong> To avoid doubt, the notice may be included in the written response under clause 20.2.</p><p><strong>20.5</strong> Effect of conversion</p><p><strong>(a)</strong> An Employee is taken, on and after the day specified in a notice for the purposes of subclause 20.4(a)(iii), to be a full-time Employee or a part-time Employee of the Employer.</p><p><strong>(b)</strong> Casual loading will cease, and, subject to <a href="/eba/ebas/nurses-midwives/leave/70-long-service-leave.html">clause 70.6</a>, any benefits relating to permanent employment will commence on the day specified in a notice for the purposes of subclause 20.4(a)(iii).</p><p>Plain language terms: casual to permanent, conversion to permanent.</p>',45)])])}const d=t(n,[["render",i]]);export{g as __pageData,d as default};
